from __future__ import annotations

import os
import io
import json
import sqlite3
import threading
import pickle
from datetime import datetime
from typing import Optional, List, Dict, Any

import numpy as np
from PIL import Image
from fastapi import FastAPI, HTTPException, UploadFile, File, Form
from pydantic import BaseModel
from sklearn.linear_model import LogisticRegression

DB_PATH = os.getenv("LABELING_DB_PATH", "labeling.db")
MODEL_PATH = os.getenv("LABELING_MODEL_PATH", "trained_model.pkl")

app = FastAPI(title="Crowdsourced Data Labeling System")
db_lock = threading.Lock()


def get_conn():
    conn = sqlite3.connect(DB_PATH, check_same_thread=False)
    conn.row_factory = sqlite3.Row
    return conn


def init_db():
    with db_lock:
        conn = get_conn()
        cur = conn.cursor()
        cur.execute(
            """
            CREATE TABLE IF NOT EXISTS images (
                id INTEGER PRIMARY KEY AUTOINCREMENT,
                filename TEXT NOT NULL,
                image_bytes BLOB NOT NULL,
                created_at TEXT NOT NULL
            )
            """
        )
        cur.execute(
            """
            CREATE TABLE IF NOT EXISTS annotations (
                id INTEGER PRIMARY KEY AUTOINCREMENT,
                image_id INTEGER NOT NULL,
                annotator_id TEXT NOT NULL,
                label TEXT NOT NULL,
                created_at TEXT NOT NULL,
                UNIQUE(image_id, annotator_id),
                FOREIGN KEY(image_id) REFERENCES images(id)
            )
            """
        )
        conn.commit()
        conn.close()


@app.on_event("startup")
def startup():
    init_db()


class AnnotationIn(BaseModel):
    image_id: int
    annotator_id: str
    label: str


class TrainResponse(BaseModel):
    trained_samples: int
    classes: List[str]
    model_path: str


def image_to_feature_vector(image_bytes: bytes, size=(64, 64)) -> np.ndarray:
    img = Image.open(io.BytesIO(image_bytes)).convert("RGB")
    img = img.resize(size)
    arr = np.asarray(img, dtype=np.float32) / 255.0
    return arr.flatten()


def get_image(image_id: int) -> Optional[sqlite3.Row]:
    with db_lock:
        conn = get_conn()
        cur = conn.cursor()
        cur.execute("SELECT * FROM images WHERE id = ?", (image_id,))
        row = cur.fetchone()
        conn.close()
        return row


def get_majority_labels() -> List[Dict[str, Any]]:
    with db_lock:
        conn = get_conn()
        cur = conn.cursor()
        cur.execute("SELECT id, image_bytes FROM images")
        images = cur.fetchall()

        results = []
        for img in images:
            cur.execute(
                """
                SELECT label, COUNT(*) as cnt
                FROM annotations
                WHERE image_id = ?
                GROUP BY label
                ORDER BY cnt DESC, label ASC
                """,
                (img["id"],),
            )
            votes = cur.fetchall()
            if not votes:
                continue
            top_count = votes[0]["cnt"]
            top_labels = [v["label"] for v in votes if v["cnt"] == top_count]
            majority_label = sorted(top_labels)[0]
            results.append(
                {
                    "image_id": img["id"],
                    "image_bytes": img["image_bytes"],
                    "label": majority_label,
                    "vote_count": top_count,
                }
            )
        conn.close()
        return results


@app.get("/health")
def health():
    return {"status": "ok", "time": datetime.utcnow().isoformat()}


@app.post("/images")
async def upload_image(file: UploadFile = File(...)):
    content = await file.read()
    if not content:
        raise HTTPException(status_code=400, detail="Empty file")
    try:
        Image.open(io.BytesIO(content)).verify()
    except Exception:
        raise HTTPException(status_code=400, detail="Invalid image file")

    with db_lock:
        conn = get_conn()
        cur = conn.cursor()
        cur.execute(
            "INSERT INTO images (filename, image_bytes, created_at) VALUES (?, ?, ?)",
            (file.filename or "image", content, datetime.utcnow().isoformat()),
        )
        image_id = cur.lastrowid
        conn.commit()
        conn.close()

    return {"image_id": image_id, "filename": file.filename}


@app.post("/annotations")
def submit_annotation(annotation: AnnotationIn):
    if not annotation.annotator_id.strip():
        raise HTTPException(status_code=400, detail="annotator_id is required")
    if not annotation.label.strip():
        raise HTTPException(status_code=400, detail="label is required")

    image = get_image(annotation.image_id)
    if not image:
        raise HTTPException(status_code=404, detail="Image not found")

    with db_lock:
        conn = get_conn()
        cur = conn.cursor()
        try:
            cur.execute(
                """
                INSERT INTO annotations (image_id, annotator_id, label, created_at)
                VALUES (?, ?, ?, ?)
                ON CONFLICT(image_id, annotator_id)
                DO UPDATE SET label = excluded.label, created_at = excluded.created_at
                """,
                (
                    annotation.image_id,
                    annotation.annotator_id.strip(),
                    annotation.label.strip(),
                    datetime.utcnow().isoformat(),
                ),
            )
            conn.commit()
        finally:
            conn.close()

    return {
        "status": "accepted",
        "image_id": annotation.image_id,
        "annotator_id": annotation.annotator_id,
        "label": annotation.label,
    }


@app.get("/images/{image_id}/annotations")
def list_annotations(image_id: int):
    image = get_image(image_id)
    if not image:
        raise HTTPException(status_code=404, detail="Image not found")

    with db_lock:
        conn = get_conn()
        cur = conn.cursor()
        cur.execute(
            """
            SELECT annotator_id, label, created_at
            FROM annotations
            WHERE image_id = ?
            ORDER BY created_at ASC
            """,
            (image_id,),
        )
        rows = cur.fetchall()
        conn.close()

    return {
        "image_id": image_id,
        "annotations": [
            {
                "annotator_id": r["annotator_id"],
                "label": r["label"],
                "created_at": r["created_at"],
            }
            for r in rows
        ],
    }


@app.get("/aggregate")
def aggregate_labels():
    aggregated = get_majority_labels()
    return {
        "items": [
            {
                "image_id": item["image_id"],
                "label": item["label"],
                "vote_count": item["vote_count"],
            }
            for item in aggregated
        ]
    }


@app.post("/train", response_model=TrainResponse)
def train_model():
    aggregated = get_majority_labels()
    if len(aggregated) < 2:
        raise HTTPException(status_code=400, detail="Need at least 2 labeled images to train")

    X = []
    y = []
    for item in aggregated:
        X.append(image_to_feature_vector(item["image_bytes"]))
        y.append(item["label"])

    unique_classes = sorted(set(y))
    if len(unique_classes) < 2:
        raise HTTPException(status_code=400, detail="Need at least 2 distinct classes to train")

    X = np.vstack(X)
    y = np.array(y)

    model = LogisticRegression(max_iter=1000)
    model.fit(X, y)

    payload = {
        "model": model,
        "classes": unique_classes,
        "trained_at": datetime.utcnow().isoformat(),
        "num_samples": int(len(y)),
    }

    with open(MODEL_PATH, "wb") as f:
        pickle.dump(payload, f)

    return TrainResponse(
        trained_samples=int(len(y)),
        classes=unique_classes,
        model_path=MODEL_PATH,
    )


@app.post("/predict")
async def predict(file: UploadFile = File(...)):
    if not os.path.exists(MODEL_PATH):
        raise HTTPException(status_code=404, detail="Model not found. Train the model first.")

    content = await file.read()
    if not content:
        raise HTTPException(status_code=400, detail="Empty file")

    try:
        features = image_to_feature_vector(content).reshape(1, -1)
    except Exception:
        raise HTTPException(status_code=400, detail="Invalid image file")

    with open(MODEL_PATH, "rb") as f:
        payload = pickle.load(f)

    model = payload["model"]
    pred = model.predict(features)[0]
    probs = None
    if hasattr(model, "predict_proba"):
        p = model.predict_proba(features)[0]
        probs = {cls: float(prob) for cls, prob in zip(model.classes_, p)}

    return {
        "predicted_label": pred,
        "probabilities": probs,
    }


@app.get("/stats")
def stats():
    with db_lock:
        conn = get_conn()
        cur = conn.cursor()
        cur.execute("SELECT COUNT(*) as c FROM images")
        image_count = cur.fetchone()["c"]
        cur.execute("SELECT COUNT(*) as c FROM annotations")
        annotation_count = cur.fetchone()["c"]
        cur.execute("SELECT COUNT(DISTINCT annotator_id) as c FROM annotations")
        annotator_count = cur.fetchone()["c"]
        conn.close()

    aggregated = get_majority_labels()

    return {
        "images": image_count,
        "annotations": annotation_count,
        "annotators": annotator_count,
        "aggregated_labeled_images": len(aggregated),
        "model_exists": os.path.exists(MODEL_PATH),
    }


